def build_report(tasks):
    done_count = 0
    lines = ["SMART TASK TRACKER REPORT", f"Total tasks: {len(tasks)}"]

    for task in tasks:
        if task.done:
            done_count += 1

    open_count = len(tasks) - done_count
    lines.append(f"Done tasks: {done_count}")
    lines.append(f"Open tasks: {open_count}")

    for task in tasks:
        lines.append(task.summary_line())

    return "\n".join(lines)


